import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
  CheckIcon,
  XIcon,
  UserIcon,
  CalendarIcon,
  BookOpenIcon,
  InboxIcon,
  MenuIcon
} from 'lucide-react';
import { StatusBadge } from '../components/StatusBadge';

const INITIAL_INBOX = [
  { id: 'REQ-201', student: 'Alex Rivera', subject: 'Python Tutoring', time: 'Today, 4:00 PM' },
  { id: 'REQ-202', student: 'Sam Taylor', subject: 'Calculus Help', time: 'Tomorrow, 10:00 AM' },
  { id: 'REQ-203', student: 'Jordan Lee', subject: 'Statistics Review', time: 'Oct 28, 2:30 PM' }
];

const INITIAL_ACCEPTED = [
  {
    id: 'ACC-301',
    student: 'Alex Rivera',
    subject: 'Python Tutoring',
    date: 'Oct 24, 2023 • 2:00 PM',
    status: 'scheduled'
  },
  {
    id: 'ACC-302',
    student: 'Sam Taylor',
    subject: 'Calculus Help',
    date: 'Oct 26, 2023 • 10:00 AM',
    status: 'accepted'
  },
  {
    id: 'ACC-303',
    student: 'Jordan Lee',
    subject: 'Statistics Review',
    date: 'Oct 28, 2023 • 2:30 PM',
    status: 'accepted'
  }
];

export function VolunteerDashboard() {
  const [activeTab, setActiveTab] = useState('incoming');
  const [inbox, setInbox] = useState(INITIAL_INBOX);
  const [acceptedCourses, setAcceptedCourses] = useState(INITIAL_ACCEPTED);
  const [acceptedCount, setAcceptedCount] = useState(1);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const dailyLimit = 3;

  const handleAction = (id, action) => {
    if (action === 'accept' && acceptedCount >= dailyLimit) {
      alert("You've reached your daily limit of sessions!");
      return;
    }

    const request = inbox.find((req) => req.id === id);
    setInbox((prev) => prev.filter((req) => req.id !== id));

    if (action === 'accept' && request) {
      setAcceptedCount((prev) => prev + 1);
      setAcceptedCourses((prev) => [
        ...prev,
        {
          id: `ACC-${Date.now()}`,
          student: request.student,
          subject: request.subject,
          date: request.time,
          status: 'accepted'
        }
      ]);
    }
  };

  const handleMarkComplete = (id) => {
    setAcceptedCourses((prev) =>
      prev.map((course) => (course.id === id ? { ...course, status: 'completed' } : course))
    );
  };

  const limitPercentage = (acceptedCount / dailyLimit) * 100;
  const isNearLimit = acceptedCount >= dailyLimit - 1;

  const contentVariants = {
    hidden: { opacity: 0, x: 10 },
    visible: { opacity: 1, x: 0, transition: { duration: 0.3 } },
    exit: { opacity: 0, x: -10, transition: { duration: 0.2 } }
  };

  return (
    <div className="flex flex-col md:flex-row min-h-[calc(100vh-73px)] bg-gray-50">
      <div className="md:hidden bg-white border-b border-gray-200 p-4 flex justify-between items-center sticky top-0 z-20">
        <span className="font-semibold text-gray-900">Volunteer Dashboard</span>
        <button onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)} className="p-2 text-gray-500 hover:bg-gray-100 rounded-md">
          <MenuIcon className="w-5 h-5" />
        </button>
      </div>

      <div className={`${isMobileMenuOpen ? 'block' : 'hidden'} md:block w-full md:w-64 bg-white border-r border-gray-200 flex-shrink-0 md:sticky md:top-[73px] md:h-[calc(100vh-73px)] overflow-y-auto z-10`}>
        <div className="p-6 border-b border-gray-100">
          <div className="flex items-center space-x-3">
            <div className="w-10 h-10 rounded-full bg-indigo-100 flex items-center justify-center text-indigo-700 font-bold text-lg">V</div>
            <div>
              <h2 className="text-sm font-bold text-gray-900">Volunteer Portal</h2>
              <p className="text-xs text-gray-500">Manage your sessions</p>
            </div>
          </div>
        </div>

        <nav className="p-4 space-y-1">
          <button
            onClick={() => {
              setActiveTab('incoming');
              setIsMobileMenuOpen(false);
            }}
            className={`w-full flex items-center justify-between px-3 py-2.5 text-sm font-medium rounded-md transition-colors ${
              activeTab === 'incoming'
                ? 'bg-indigo-50 text-indigo-700 border-l-2 border-indigo-600'
                : 'text-gray-600 hover:bg-gray-50 hover:text-gray-900 border-l-2 border-transparent'
            }`}
          >
            <div className="flex items-center">
              <InboxIcon className={`w-5 h-5 mr-3 ${activeTab === 'incoming' ? 'text-indigo-600' : 'text-gray-400'}`} />
              Incoming Requests
            </div>
            {inbox.length > 0 && (
              <span className="inline-flex items-center justify-center px-2 py-0.5 text-xs font-bold rounded-full bg-indigo-100 text-indigo-700">
                {inbox.length}
              </span>
            )}
          </button>

          <button
            onClick={() => {
              setActiveTab('accepted');
              setIsMobileMenuOpen(false);
            }}
            className={`w-full flex items-center px-3 py-2.5 text-sm font-medium rounded-md transition-colors ${
              activeTab === 'accepted'
                ? 'bg-indigo-50 text-indigo-700 border-l-2 border-indigo-600'
                : 'text-gray-600 hover:bg-gray-50 hover:text-gray-900 border-l-2 border-transparent'
            }`}
          >
            <BookOpenIcon className={`w-5 h-5 mr-3 ${activeTab === 'accepted' ? 'text-indigo-600' : 'text-gray-400'}`} />
            Accepted Courses
          </button>
        </nav>
      </div>

      <div className="flex-1 p-4 sm:p-6 lg:p-8 overflow-x-hidden">
        <AnimatePresence mode="wait">
          {activeTab === 'incoming' && (
            <motion.div key="incoming" variants={contentVariants} initial="hidden" animate="visible" exit="exit" className="max-w-4xl mx-auto">
              <div className="mb-8 flex flex-col sm:flex-row sm:items-end justify-between gap-4">
                <div>
                  <h1 className="text-2xl font-bold text-gray-900">Incoming Requests</h1>
                  <p className="text-gray-500 mt-1">Review and accept new tutoring sessions.</p>
                </div>

                <div className="bg-white p-4 rounded-xl border border-gray-200 shadow-sm w-full sm:w-64">
                  <div className="flex justify-between items-center mb-2">
                    <span className="text-sm font-medium text-gray-700">Daily Limit</span>
                    <span className={`text-sm font-bold ${isNearLimit ? 'text-amber-600' : 'text-indigo-600'}`}>
                      {acceptedCount} / {dailyLimit} Sessions
                    </span>
                  </div>
                  <div className="w-full bg-gray-100 rounded-full h-2.5 overflow-hidden">
                    <motion.div
                      initial={{ width: 0 }}
                      animate={{ width: `${limitPercentage}%` }}
                      transition={{ duration: 0.5, ease: 'easeOut' }}
                      className={`h-2.5 rounded-full ${
                        acceptedCount >= dailyLimit ? 'bg-red-500' : isNearLimit ? 'bg-amber-500' : 'bg-indigo-600'
                      }`}
                    />
                  </div>
                  {acceptedCount >= dailyLimit && (
                    <p className="text-xs text-red-600 mt-2 font-medium">Daily limit reached. Take a break!</p>
                  )}
                </div>
              </div>

              <div className="space-y-4">
                <AnimatePresence>
                  {inbox.map((request) => (
                    <motion.div
                      key={request.id}
                      initial={{ opacity: 0, y: 10 }}
                      animate={{ opacity: 1, y: 0 }}
                      exit={{ opacity: 0, scale: 0.95, transition: { duration: 0.2 } }}
                      className="bg-white rounded-xl border border-gray-200 p-5 shadow-sm flex flex-col sm:flex-row sm:items-center justify-between gap-4"
                    >
                      <div className="flex items-start space-x-4">
                        <div className="h-10 w-10 rounded-full bg-indigo-50 flex items-center justify-center flex-shrink-0">
                          <UserIcon className="w-5 h-5 text-indigo-600" />
                        </div>
                        <div>
                          <h3 className="text-base font-bold text-gray-900">{request.student}</h3>
                          <div className="flex flex-col sm:flex-row sm:items-center text-sm text-gray-500 mt-1 gap-1 sm:gap-3">
                            <span className="flex items-center">
                              <BookOpenIcon className="w-3.5 h-3.5 mr-1" /> {request.subject}
                            </span>
                            <span className="hidden sm:inline text-gray-300">•</span>
                            <span className="flex items-center text-indigo-600 font-medium">
                              <CalendarIcon className="w-3.5 h-3.5 mr-1" /> {request.time}
                            </span>
                          </div>
                        </div>
                      </div>

                      <div className="flex items-center space-x-2 w-full sm:w-auto mt-2 sm:mt-0">
                        <motion.button
                          whileTap={{ scale: 0.95 }}
                          onClick={() => handleAction(request.id, 'reject')}
                          className="flex-1 sm:flex-none px-4 py-2 border border-red-200 text-red-600 bg-white hover:bg-red-50 rounded-lg text-sm font-medium transition-colors flex items-center justify-center"
                        >
                          <XIcon className="w-4 h-4 mr-1.5" /> Reject
                        </motion.button>
                        <motion.button
                          whileTap={{ scale: 0.95 }}
                          onClick={() => handleAction(request.id, 'accept')}
                          disabled={acceptedCount >= dailyLimit}
                          className={`flex-1 sm:flex-none px-4 py-2 rounded-lg text-sm font-medium transition-colors flex items-center justify-center text-white ${
                            acceptedCount >= dailyLimit ? 'bg-gray-300 cursor-not-allowed' : 'bg-indigo-600 hover:bg-indigo-700 shadow-sm'
                          }`}
                        >
                          <CheckIcon className="w-4 h-4 mr-1.5" /> Accept
                        </motion.button>
                      </div>
                    </motion.div>
                  ))}
                </AnimatePresence>

                {inbox.length === 0 && (
                  <div className="bg-white rounded-xl border border-gray-200 border-dashed p-10 text-center">
                    <div className="w-12 h-12 bg-gray-50 rounded-full flex items-center justify-center mx-auto mb-3">
                      <CheckIcon className="w-6 h-6 text-gray-400" />
                    </div>
                    <h3 className="text-lg font-medium text-gray-900">All caught up!</h3>
                    <p className="text-gray-500 mt-1">You have no pending requests at the moment.</p>
                  </div>
                )}
              </div>
            </motion.div>
          )}

          {activeTab === 'accepted' && (
            <motion.div key="accepted" variants={contentVariants} initial="hidden" animate="visible" exit="exit" className="max-w-5xl mx-auto">
              <div className="mb-8">
                <h1 className="text-2xl font-bold text-gray-900">Accepted Courses</h1>
                <p className="text-gray-500 mt-1">Manage your ongoing and scheduled sessions.</p>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {acceptedCourses.map((course) => (
                  <motion.div
                    key={course.id}
                    layout
                    initial={{ opacity: 0, scale: 0.95 }}
                    animate={{ opacity: 1, scale: 1 }}
                    className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden flex flex-col"
                  >
                    <div className="p-5 flex-1">
                      <div className="flex justify-between items-start mb-4">
                        <div className="flex items-center space-x-3">
                          <div className="w-10 h-10 rounded-full bg-indigo-100 flex items-center justify-center text-indigo-700 font-bold text-sm">
                            {course.student
                              .split(' ')
                              .map((n) => n[0])
                              .join('')}
                          </div>
                          <div>
                            <h3 className="text-base font-bold text-gray-900">{course.student}</h3>
                            <p className="text-sm text-gray-500 flex items-center mt-0.5">
                              <BookOpenIcon className="w-3.5 h-3.5 mr-1" /> {course.subject}
                            </p>
                          </div>
                        </div>
                        <StatusBadge status={course.status} />
                      </div>

                      <div className="flex items-center text-sm text-gray-600 bg-gray-50 p-3 rounded-lg border border-gray-100">
                        <CalendarIcon className="w-4 h-4 mr-2 text-gray-400" />
                        {course.date}
                      </div>
                    </div>

                    <div className="p-4 border-t border-gray-100 bg-gray-50/50">
                      {course.status !== 'completed' ? (
                        <motion.button
                          whileTap={{ scale: 0.98 }}
                          onClick={() => handleMarkComplete(course.id)}
                          className="w-full py-2 bg-indigo-600 hover:bg-indigo-700 text-white text-sm font-medium rounded-lg shadow-sm transition-colors focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500 flex justify-center items-center"
                        >
                          <CheckIcon className="w-4 h-4 mr-1.5" /> Mark as Complete
                        </motion.button>
                      ) : (
                        <div className="w-full py-2 bg-gray-100 text-gray-500 text-sm font-medium rounded-lg flex justify-center items-center cursor-default">
                          <CheckIcon className="w-4 h-4 mr-1.5" /> Session Completed
                        </div>
                      )}
                    </div>
                  </motion.div>
                ))}

                {acceptedCourses.length === 0 && (
                  <div className="col-span-full bg-white rounded-xl border border-gray-200 border-dashed p-10 text-center">
                    <BookOpenIcon className="w-12 h-12 text-gray-300 mx-auto mb-3" />
                    <h3 className="text-lg font-medium text-gray-900">No accepted courses yet</h3>
                    <p className="text-gray-500 mt-1">Accept incoming requests to see them here.</p>
                  </div>
                )}
              </div>
            </motion.div>
          )}
        </AnimatePresence>
      </div>
    </div>
  );
}
